import java.util.Queue;
import java.util.LinkedList;

public class Solution {
    public static long solve(long[][] grid, long k) {
        long count = 0;
        int m = grid.length;
        int n = grid[0].length;

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] != 0) {
                    long sum = 0;
                    Queue<int[]> queue = new LinkedList<>();
                    queue.add(new int[]{i, j});
                    while (!queue.isEmpty()) {
                        int[] current = queue.poll();
                        int x = current[0];
                        int y = current[1];
                        sum += grid[x][y];
                        grid[x][y] = 0;
                        int[] dx = {-1, 1, 0, 0};
                        int[] dy = {0, 0, -1, 1};
                        for (int d = 0; d < 4; d++) {
                            int nx = x + dx[d];
                            int ny = y + dy[d];
                            if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] != 0) {
                                queue.add(new int[]{nx, ny});
                            }
                        }
                    }
                    if (sum % k == 0) {
                        count++;
                    }
                }
            }
        }
        return count;
    }
}
