                    long sum = 0;
                    Queue<int[]> queue = new LinkedList<>();
                    queue.add(new int[]{i, j});
                    while (!queue.isEmpty()) {
                        int[] curr = queue.poll();
                        int x = curr[0];
                        int y = curr[1];
                        sum += grid[x][y];
                        grid[x][y] = 0;
                        int[] dx = {-1, 1, 0, 0};
                        int[] dy = {0, 0, -1, 1};
